local RecordListCache = {}
local RecordBuilder = MaxRecordBuilder.new()

MaxRecordHelper = {}

local function updateRecordCache(key, value, score)
    value = tostring(value)
    score = tonumber(score)
    local recordList = RecordListCache[tostring(key)]
    local needInsert = false
    if recordList then
        local cache = recordList.cache
        for index, record in pairs(cache) do
            if record[1] == value then
                if record[2] >= score then
                    ---this max record had exist
                    return false
                else
                    table.remove(cache, index)
                    break
                end
            end
        end

        if #cache < recordList.maxRecordCount or score > cache[#cache][2] then
            table.insert(cache, { value, score })
            needInsert = true
        end

        table.sort(cache, function(a, b)
            return a[2] > b[2]
        end)
        if #cache > recordList.maxRecordCount then
            table.remove(cache, #cache)
        end
    end
    return needInsert
end

local function syncRecord(list, key, userId, requestId)
    local player = PlayerManager:getPlayerByUserId(userId)
    if player then
        RecordBuilder:getRecordStart(key, list, function()
            local result = {}
            for _, record in pairs(list) do
                record[1] = RecordBuilder:buildValue(key, record[1]) or record[1]
                table.insert(result, table.concat(record, ":"))
            end
            local data = table.concat(result, "'")
            local builder = DataBuilder.new():fromTable({
                records = data,
                key = key,
                requestId = requestId
            })
            PacketSender:sendLuaCommonData(player.rakssid, "SyncRecords", builder:getData())
        end)
    end
end

function MaxRecordHelper:init()
    for key, recordList in pairs(RecordListCache) do
        self:requestNewData(key, recordList.maxRecordCount)
    end

    EventObservable:registerDataCallBack("GetRecord", function(userId, builder)
        self:getRecordFromClient(builder:getParam("key"), builder:getParam("endIndex"), userId, builder:getParam("requestId"))
    end, DataBuilderProcessor)
end

function MaxRecordHelper:registerRecordBuilder(builderClass)
    if builderClass.super.__cname == "MaxRecordBuilder" then
        RecordBuilder = builderClass.new()
    end
end

function MaxRecordHelper:requestNewData(key, maxRecordCount, callback)
    WebService:GetRecordList(key, 0, maxRecordCount, function(data)
        if not data then
            print("http GetRecordList for key = " .. key .. " ,failed!")
            return
        end
        for _, record in pairs(data) do
            --updateRecordCache(key, record.member, record.score)
            MaxRecordHelper:receiveBroadcast(key, record.member, record.score)
        end
        if callback then
            callback()
        end
    end)
end

function MaxRecordHelper:addGameRecord(key, maxRecordCount)
    RecordListCache[tostring(key)] = {
        maxRecordCount = maxRecordCount,
        cache = {},
        clientCache = {}
    }
end

---遇到相同的key,value的数据 score值累加
function MaxRecordHelper:reportOneRecord(key, value, score)
    local RecordList = RecordListCache[tostring(key)]
    ---更新缓存数据 ,不满足插入条件 return
    if not RecordList or not MaxRecordHelper:receiveBroadcast(key, value, score) then
        return
    end
    print("insert success")
    ---提交给后台
    WebService:ReportOneRecord(key, value, score, function(_, code)
        if code ~= 1 then
            print("ReportOneRecord Fail")
        end
    end, RecordList.maxRecordCount)
end

---根据startIndex ,endIndex 组成的区间查询 key记录榜
function MaxRecordHelper:getRecord(key, page, size, callback)
    local recordList = RecordListCache[tostring(key)]
    local list = {}
    if recordList then
        local startIndex = (page - 1) * size + 1
        local endIndex = page * size
        for i = startIndex, endIndex do
            if recordList.cache[i] then
                table.insert(list, {
                    rank = i,
                    value = recordList.cache[i][1],
                    score = recordList.cache[i][2]
                })
            end
        end
    end
    callback(list)
end

function MaxRecordHelper:getRecordFromClient(key, requestEndIndex, userId, requestId)
    local needSyncList = {}
    local recordList = RecordListCache[tostring(key)]
    if recordList then
        local cache = recordList.cache
        local nowEndIndex = recordList.clientCache[tostring(userId)] or 0
        for i = nowEndIndex + 1, requestEndIndex do
            if i <= #cache then
                local record = cache[i]
                table.insert(needSyncList, { record[1], record[2] })
                recordList.clientCache[tostring(userId)] = i
            end
        end
    end
    syncRecord(needSyncList, key, userId, requestId)
end

---未接通
function MaxRecordHelper:receiveBroadcast(key, value, score)
    local needInsert = updateRecordCache(key, value, score)
    local needSyncList = { { value, score } }
    local recordList = RecordListCache[tostring(key)]
    if recordList and needInsert then
        local thisRecordIndex = 0
        ---找到该数据插入的位置
        for index, record in pairs(recordList.cache) do
            if record[1] == tostring(value) and record[2] == tonumber(score) then
                thisRecordIndex = index
            end
        end
        ---同步该条数据给满足条件的客户端, 已缓存数据包含该位置
        if thisRecordIndex ~= 0 then
            for userId, nowEndIndex in pairs(recordList.clientCache) do
                if thisRecordIndex < nowEndIndex then
                    syncRecord(needSyncList, key, userId)
                end
            end
        end
    end
    return needInsert
end

function MaxRecordHelper:onPlayerLogout(userId)
    for _, recordList in pairs(RecordListCache) do
        if recordList.clientCache then
            recordList.clientCache[tostring(userId)] = nil
        end
    end
end